import{c as t,Q as a,j as n,m as r}from"./chunks/framework.DpF7k2f3.js";const m=JSON.parse('{"title":"Chapter 11: Agent & Skill Development","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part3-practice/chapter11.md","filePath":"en/part3-practice/chapter11.md"}'),i={name:"en/part3-practice/chapter11.md"};function o(l,e,s,c,p,h){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="chapter-11-agent-skill-development" tabindex="-1">Chapter 11: Agent &amp; Skill Development <a class="header-anchor" href="#chapter-11-agent-skill-development" aria-label="Permalink to &quot;Chapter 11: Agent &amp; Skill Development&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understanding the essential difference between Agent Assistants and regular Agents</li><li>Mastering the three-layer architecture of memory systems: short-term, long-term, working memory</li><li>Learning to develop a complete Skill from scratch, including design principles and error handling</li><li>Understanding Skill registration/discovery mechanisms and composition workflow design</li><li>Comparing Coze, Dify, and LangGraph frameworks for different scenarios</li><li>Getting a runnable AI development assistant complete code</li><li>Understanding Agent evaluation systems and commercialization paths</li></ul><p>2024 was the first year of Agents. But I want to tell you something else: 2024 was also the beginning of nightmares for Agent Assistant product managers.</p><p>Because the word &quot;Agent&quot; has been overused. Everything can be called Agent, but nothing is truly an Agent. So in this chapter, I&#39;m going to clarify: what exactly is an Agent Assistant, what&#39;s the difference from regular Agents, and why this difference matters.</p><p>The special focus is on Skill development—turning Agents from &quot;good talkers&quot; to &quot;capable doers.&quot;</p><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter11.html">阅读中文版</a></p></blockquote>',8)])])}const g=t(i,[["render",o]]);export{m as __pageData,g as default};
